import{_ as t,a}from"./chunks/频繁报错提示.B4wBXruJ.js";import{_ as n,o as d,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"Uploadlimieten voor gebruikers","description":"","frontmatter":{},"headers":[],"relativePath":"nl-NL/Safety/user-rate-limits.md","filePath":"nl-NL/Safety/user-rate-limits.md","lastUpdated":1781962217000}'),o={name:"nl-NL/Safety/user-rate-limits.md"};function l(s,e,p,b,u,g){return d(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="uploadlimieten-voor-gebruikers" tabindex="-1">Uploadlimieten voor gebruikers <a class="header-anchor" href="#uploadlimieten-voor-gebruikers" aria-label="Permalink to &quot;Uploadlimieten voor gebruikers&quot;">​</a></h1><p>Uploadlimieten bepalen hoe vaak gewone gebruikers of bezoekers vanaf de homepage bestanden mogen uploaden. Dit helpt misbruik van openbare uploadpagina&#39;s voorkomen.</p><p>Deze functie geldt alleen voor uploads vanaf de homepage. Beheerdersuploads en uploads met API Tokens worden niet door deze gebruikerslimieten beperkt.</p><h2 id="waar-je-dit-configureert" tabindex="-1">Waar je dit configureert <a class="header-anchor" href="#waar-je-dit-configureert" aria-label="Permalink to &quot;Waar je dit configureert&quot;">​</a></h2><p>Open het beheer en ga naar:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; User Rate Limits</span></span></code></pre></div><p><img src="'+t+'" alt="Instellingen gebruikerslimieten" loading="lazy"></p><h2 id="limieten-inschakelen" tabindex="-1">Limieten inschakelen <a class="header-anchor" href="#limieten-inschakelen" aria-label="Permalink to &quot;Limieten inschakelen&quot;">​</a></h2><p>Nadat <code>Enable Rate Limits</code> is ingeschakeld, houdt ImgBed recente uploads bij op basis van het IP-adres van de uploader.</p><p>Standaardwaarden:</p><table tabindex="0"><thead><tr><th>Instelling</th><th>Standaard</th><th>Beschrijving</th></tr></thead><tbody><tr><td>Detectievenster</td><td>1,5 uur</td><td>Hoe ver terug uploadrecords worden meegeteld.</td></tr><tr><td>Maximaal aantal bestanden</td><td>20</td><td>Maximum aantal bestanden binnen het detectievenster.</td></tr><tr><td>Limiet per bestand</td><td>20 MB</td><td>Maximale grootte van één bestand.</td></tr><tr><td>Totale uploadlimiet</td><td>200 MB</td><td>Maximale totale uploadgrootte binnen het detectievenster.</td></tr></tbody></table><p>Bijvoorbeeld: met een venster van 1,5 uur, 20 bestanden, 20 MB per bestand en 200 MB totaal worden uploads vanaf hetzelfde IP geblokkeerd zodra één ingestelde limiet wordt overschreden.</p><h2 id="bestandstypen-uitsluiten" tabindex="-1">Bestandstypen uitsluiten <a class="header-anchor" href="#bestandstypen-uitsluiten" aria-label="Permalink to &quot;Bestandstypen uitsluiten&quot;">​</a></h2><p><code>Excluded upload file types</code> blokkeert gewone gebruikers of bezoekers voor geselecteerde bestandscategorieën.</p><p>Beschikbare categorieën:</p><table tabindex="0"><thead><tr><th>Type</th><th>Beschrijving</th></tr></thead><tbody><tr><td>Images</td><td>jpg, png, webp, gif en vergelijkbare afbeeldingsbestanden</td></tr><tr><td>Videos</td><td>mp4, webm, mov en vergelijkbare videobestanden</td></tr><tr><td>Audio</td><td>mp3, flac, wav en vergelijkbare audiobestanden</td></tr><tr><td>Documents</td><td>pdf, txt, md, docx en vergelijkbare documentbestanden</td></tr><tr><td>Other</td><td>Bestanden buiten de bovenstaande categorieën, zoals zip, rar, exe, apk</td></tr></tbody></table><p>Standaard is een type niet geselecteerd, wat betekent dat het is toegestaan.</p><p>Klik je op een type en wordt het gemarkeerd, dan is dat type geblokkeerd.</p><p>Als <code>Other</code> is geselecteerd, worden bezoekers die zip- of rar-bestanden uploaden geblokkeerd en krijgen ze te zien dat dit bestandstype niet wordt ondersteund.</p><h2 id="blokkeermeldingen" tabindex="-1">Blokkeermeldingen <a class="header-anchor" href="#blokkeermeldingen" aria-label="Permalink to &quot;Blokkeermeldingen&quot;">​</a></h2><p>Wanneer een limiet wordt geraakt, zien gebruikers een passende melding:</p><p><img src="'+a+'" alt="Melding te vaak uploaden" loading="lazy"></p><table tabindex="0"><thead><tr><th>Situatie</th><th>Betekenis van de melding</th></tr></thead><tbody><tr><td>Eén bestand te groot</td><td>Het bestand is te groot en moet vóór upload worden gecomprimeerd.</td></tr><tr><td>Bestandstype geblokkeerd</td><td>Dit bestandstype wordt niet ondersteund. Verwijder het en probeer opnieuw.</td></tr><tr><td>Uploads te vaak</td><td>Recente uploads zijn te frequent; er wordt een retrytijd getoond.</td></tr><tr><td>Totale grootte te hoog</td><td>De recente totale uploadgrootte is te hoog; er wordt een retrytijd getoond.</td></tr></tbody></table><h2 id="wanneer-inschakelen" tabindex="-1">Wanneer inschakelen <a class="header-anchor" href="#wanneer-inschakelen" aria-label="Permalink to &quot;Wanneer inschakelen&quot;">​</a></h2><p>Schakel gebruikerslimieten in als je uploadhomepage openbaar bereikbaar is.</p><p>Veelvoorkomende redenen:</p><ul><li>je maakt je zorgen over geautomatiseerde bulkuploads.</li><li>je wilt grote uploads van bezoekers beperken.</li><li>je wilt dat gewone gebruikers alleen afbeeldingen uploaden, geen archieven of installers.</li><li>je wilt openbare upload beschikbaar houden, maar resourcegebruik beheersen.</li></ul><p>Als de site alleen voor jezelf is, of alleen beheerders kunnen uploaden, kun je dit uit laten.</p>',28)])])}const k=n(o,[["render",l]]);export{c as __pageData,k as default};
